var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":null,"text":{"KOREA":"오랜 고민 끝에, 당신은 한 가지 중요한 사실을 깨달았다.","JPN":"長い間悩んだ結果、あなたは一つ大事なことに気づいた。","ENG":"After much debate, you came to the conclusion","TWN":"苦惱許久後，你意識到一個重要的事實。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":null,"text":{"KOREA":"줄곧 생각해 온 그녀야말로, 앞으로 마주할 운명에서 꼭 필요한 존재라는 것을.","JPN":"ずっと考えてきた彼女だからこそ、これから向き合う運命に必ず必要な存在であることを。","ENG":"that this employee, whom you'd been giving a lot of thought to, was absolutely necessary for the future ahead.","TWN":"一直盤踞在腦海中的她，是你在未來必須要面對的命運中，一個不可或缺的存在。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L4_1","type":"dialog","speaker":null,"text":{"KOREA":"그리하여 당신은 결심했다.","JPN":"そして、あなたは決心した。","ENG":"So, you've decided","TWN":"所以你決定了。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L5_1","type":"dialog","speaker":null,"text":{"KOREA":"이 세계에서 어떤 결말을 마주하더라도, 마지막까지 그녀와 함께하기로.","JPN":"この世界でどのような結末を迎えるとしても、最後まで彼女とともにいることを。","ENG":"that you'll be with her, no matter the consequences.","TWN":"不管這個世界會迎來怎樣的結局，你都要和她一起走到最後。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L6_1","type":"dialog","speaker":null,"text":{"KOREA":"마음의 준비를 마치고 사장실로 호출하자, 곧 도착한다는 응답이 돌아왔다.","JPN":"意を決して社長室へ呼び出すと、もうすぐ着くとの応答が返ってきた。","ENG":"Having decided that, you called her to your office. She said she'd be here soon.","TWN":"下定決心後，你呼叫她到老闆辦公室，得到回應說她馬上就到。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_SILENCE","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L12_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"무슨 일이야? 갑자기 부르다니. 새로운 임무 같은 거야?","JPN":"どうしたの、急に呼び出したりして。新しい任務かしら？","ENG":"What's going on? You suddenly called me. Is it a new mission?","TWN":"有什麼事嗎？怎麼會突然找我？是有新的任務嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"응? 임무나 작전 이야기는 아니라고?","JPN":"えっ？　任務や作戦の話じゃないの？","ENG":"Hmm? It's not about a mission or an operation?","TWN":"嗯？跟任務或作戰無關的事嗎？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"이건…… 계약서? 나한테 지금 이 회사 소속이 되라는 거야?","JPN":"これは……契約書？　私にこの会社の所属になれってこと？","ENG":"This is... a contract? Are you trying to recruit me into your company?","TWN":"這是……契約？你是要將我招募進你的公司嗎？ "},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"아, 아니! 기분이 나쁘다는 말은 아니고…… 이런 건 처음이라서…… 하하.","JPN":"い、いや。別に嫌って意味じゃなくて……こういうのは初めてで……ははっ。","ENG":"N-no! It's not that I'm offended or anything, but... it's just that it's my first time being offered something like this... Ha ha.","TWN":"不，不是！我不是討厭的意思……這還是第一次……哈哈。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"회사 생활 같은 건 해본적 없어서, 이런 건 잘 모르지만…….","JPN":"会社に勤めたことがないから、こういうのってよくわからないけど……","ENG":"I've never worked at a company before, so I'm not so sure...","TWN":"我沒經歷過職場生活，所以搞不太清楚……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"어쨌든 당신도 내 실력을 인정한다는 의미겠지?","JPN":"これってつまり、あなたも私の実力を認めたって意味なんだよね？","ENG":"But I guess it just means that you see my worth, right?","TWN":"總之意思就是你認同我的實力吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"뭐, 이런 것도 썩 나쁘진 않네. 고마워.","JPN":"まあ、なんかこういうのも悪くないね。ありがとう。","ENG":"Well, it's not bad at all. Thanks.","TWN":"嗯～這樣好像也不錯，謝啦。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"이곳에 있는 동안, 를르슈…… 아니, 제로는 당신에게 협력한다고 했지?","JPN":"ここにいる間、ルルーシュ……、いえ、ゼロはあなたに協力すると言ったんだよね？","ENG":"While we're here, Lelouch... I mean, Zero, agreed to help you, right?","TWN":"在這裡的這段時間，魯路修……不，Zero會和你合作對吧？"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"KALLEN_GEASS_NULL_NULL","text":{"KOREA":"그럼, 나도 협력하겠어.","JPN":"なら、私も協力する。","ENG":"Then I'll help you too.","TWN":"好，那我也和你合作。"},"stage":{"bg":"LIFETIME","bgm":"CUTSCENE_HOPE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"KALLEN_GEASS_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);